// stableTablePagerSuppressed returns a copy of view with Pagination zeroed so
// the shared ForeignAllowlistTable's embedded components.Pagination renders
// nothing on the next/ channel. The next/ allowlist page supplies its OWN
// keyboard-wired NextPagination (appended in ForeignAllowlistBodyNext above);
// without this suppression BOTH pagers render -- the stable "Showing page X of
// Y" counter nav AND NextPagination -- because the next/ handler populates
// view.Pagination (the stable handler leaves it zero, so the stable page shows
// only one). view is passed by value, so zeroing the field here cannot affect
// the original view used to build NextPagination.
func stableTablePagerSuppressed(view templates.ForeignAllowlistPageView) templates.ForeignAllowlistPageView {
	view.Pagination = components.PaginationData{}
	return view
}

// buildAllowlistPagination converts the shared PaginationData from the view
// into a NextPaginationData for the keyboard-wired next/ pagination controls.
// Swap is set to "outerHTML" so Prev/Next replaces the entire
// #foreign-allowlist-body fragment (table + pagination) as one unit.
func buildAllowlistPagination(view templates.ForeignAllowlistPageView) NextPaginationData {
	p := view.Pagination
	prevURL := ""
	nextURL := ""
	if p.CurrentPage > 1 {
		prevURL = p.PageURL(p.CurrentPage - 1)
	}
	if p.CurrentPage < p.TotalPages {
		nextURL = p.PageURL(p.CurrentPage + 1)
	}
	npd := NewNextPagination(
		p.CurrentPage > 1,
		p.CurrentPage < p.TotalPages,
		prevURL,
		nextURL,
		"foreign-allowlist-body",
		false,
	)
	npd.Swap = "outerHTML"
	return npd
}

